import React, { useRef, useEffect } from "react";

export default function CallWindow({ currentUser, friend, socket, onEnd }) {
  const localVideo = useRef(null);
  const remoteVideo = useRef(null);
  const peerConnection = useRef(null);

  useEffect(() => {
    const startCall = async () => {
      peerConnection.current = new RTCPeerConnection();

      // Show local video
      const stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
      localVideo.current.srcObject = stream;
      stream.getTracks().forEach(track => peerConnection.current.addTrack(track, stream));

      // Remote video
      peerConnection.current.ontrack = (event) => {
        remoteVideo.current.srcObject = event.streams[0];
      };

      // ICE candidates
      peerConnection.current.onicecandidate = (event) => {
        if (event.candidate) {
          socket.emit("ice candidate", { toId: friend.userId, candidate: event.candidate });
        }
      };

      // Create offer
      const offer = await peerConnection.current.createOffer();
      await peerConnection.current.setLocalDescription(offer);
      socket.emit("call request", { fromId: currentUser.userId, toId: friend.userId, offer });
    };

    startCall();

    // Handle answer
    socket.on("call answered", async ({ answer }) => {
      await peerConnection.current.setRemoteDescription(new RTCSessionDescription(answer));
    });

    // Handle incoming ICE
    socket.on("ice candidate", async (candidate) => {
      try {
        await peerConnection.current.addIceCandidate(new RTCIceCandidate(candidate));
      } catch (err) {
        console.error("Error adding ICE candidate", err);
      }
    });

    return () => {
      socket.off("call answered");
      socket.off("ice candidate");
      peerConnection.current?.close();
    };
  }, [currentUser.userId, friend.userId, socket]);

  const endCall = () => {
    peerConnection.current?.close();
    onEnd();
  };

  return (
    <div style={styles.container}>
      <h3 style={styles.header}>Call with {friend.userId}</h3>
      <video ref={localVideo} autoPlay muted playsInline style={styles.video} />
      <video ref={remoteVideo} autoPlay playsInline style={styles.video} />
      <button style={styles.endBtn} onClick={endCall}>End Call</button>
    </div>
  );
}

const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    alignItems: "center",
    height: "100vh",
    backgroundColor: "#000",
    color: "white",
  },
  header: {
    margin: 10,
  },
  video: {
    width: "100%",
    maxHeight: "40%",
    backgroundColor: "black",
    marginBottom: 10,
  },
  endBtn: {
    padding: "10px 20px",
    fontSize: 16,
    borderRadius: 5,
    border: "none",
    backgroundColor: "#d9534f",
    color: "white",
    cursor: "pointer",
  },
};
